mapper.select:
SELECT order_no
	FROM TB_ORDER_MST
WHERE order_id = #{orderId}

mapper.update:
UPDATE TB_DOCUMENT_MST
SET memo = #{memo}
WHERE doc_id = #{docId}

mapper.select:
SELECT d.doc_id, d.doc_no, d.doc_title, d.doc_type, IFNULL(d.memo, '') AS memo, d.reg_dtime, u.user_name FROM TB_DOCUMENT_MST d LEFT JOIN TB_USERS u ON d.owner_user_id = u.user_id
u.company_cd = (SELECT company_cd FROM TB_USERS WHERE user_id = #{userId})
AND d.owner_user_id = #{userId}
AND doc_type = #{docType}
AND ( d.doc_no LIKE CONCAT('%', #{keyword}, '%') d.doc_title LIKE CONCAT('%', #{keyword}, '%') OR u.user_name LIKE CONCAT('%', #{keyword}, '%') )
ORDER BY d.doc_id DESC
